"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getRandomComplete } from "@/lib/learningMessages";
import { markStepDone } from "@/lib/progress";

// ===== 第一层：回顾内容 =====
const REVIEW_ITEMS = [
  { icon: "✋", step: "1", label: "摸一摸", text: "你翻看了日历，找到了节日和生日" },
  { icon: "⚖️", step: "2", label: "比一比", text: "你比较了 12 个月的天数，发现大月和小月" },
  { icon: "🔢", step: "3", label: "数一数", text: "你算出了平年 365 天、闰年 366 天" },
  { icon: "✏️", step: "4", label: "画一画", text: "你在时间轴上标出了重要日期" },
  { icon: "🔄", step: "5", label: "变一变", text: "你发现了每 4 年一个闰年的规律" },
  { icon: "🏠", step: "6", label: "用一用", text: "你计算了暑假、生日倒计时和上学天数" },
] as const;

const REVIEW_DURATION = 3000;

// ===== 月份基础数据 =====
const MONTHS = [
  "1月", "2月", "3月", "4月", "5月", "6月",
  "7月", "8月", "9月", "10月", "11月", "12月",
] as const;

// 口诀逐字：“一三五七八十腊”，其揭示顺序与大月揭示顺序一致
const KOUJUE_CHARS = ["一", "三", "五", "七", "八", "十", "腊"] as const;

// ===== 第二层：选择选项 =====
const CHOICE_OPTIONS = [
  { key: "A", text: "1、3、5、7、8、10、12 月有 31 天（大月）" },
  { key: "B", text: "4、6、9、11 月有 30 天（小月）" },
  { key: "C", text: "平年 2 月 28 天，闰年 2 月 29 天" },
] as const;

// ===== 第三层：验证揭示序列 =====
type RevealStep =
  | { type: "big"; monthIdx: number }
  | { type: "saying"; text: string }
  | { type: "small"; monthIdx: number }
  | { type: "feb"; text: string };

const REVEAL_STEPS: RevealStep[] = [
  { type: "big", monthIdx: 0 },
  { type: "big", monthIdx: 2 },
  { type: "big", monthIdx: 4 },
  { type: "big", monthIdx: 6 },
  { type: "big", monthIdx: 7 },
  { type: "big", monthIdx: 9 },
  { type: "big", monthIdx: 11 },
  { type: "saying", text: "三十一年永不差 —— 这些月份都是 31 天" },
  { type: "small", monthIdx: 3 },
  { type: "small", monthIdx: 5 },
  { type: "small", monthIdx: 8 },
  { type: "small", monthIdx: 10 },
  { type: "feb", text: "2 月最特别：平年 28 天，闰年 29 天" },
];

type Layer = "review" | "express" | "verify" | "card";
type ExpressTab = "fill" | "draw" | "choose";
// 画图标注状态：0 未标 / 1 大月(31) / 2 小月(30)
type MarkState = 0 | 1 | 2;

export default function DiscoverPage() {
  const [layer, setLayer] = useState<Layer>("review");
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);

  // 完成卡片出现时标记 discover 步骤完成
  useEffect(() => {
    if (layer === "card") {
      markStepDone("calendar", "discover");
    }
  }, [layer]);

  // ===== 第一层：回顾 =====
  const [reviewIdx, setReviewIdx] = useState(0);
  const reviewDone = reviewIdx >= REVIEW_ITEMS.length;

  useEffect(() => {
    if (layer !== "review") return;
    if (reviewIdx >= REVIEW_ITEMS.length) return;
    const id = setTimeout(() => setReviewIdx((p) => p + 1), REVIEW_DURATION);
    return () => clearTimeout(id);
  }, [layer, reviewIdx]);

  // ===== 第二层：表达发现 =====
  const [tab, setTab] = useState<ExpressTab>("fill");
  const [fillA, setFillA] = useState(""); // 一年有多少天
  const [fillB, setFillB] = useState(""); // 31天的月份叫什么
  const [fillC, setFillC] = useState(""); // 闰年2月有多少天
  const [marks, setMarks] = useState<MarkState[]>(
    Array.from({ length: 12 }, () => 0)
  );
  const [choices, setChoices] = useState<Set<string>>(new Set());
  const [customText, setCustomText] = useState("");

  const markCount = marks.filter((m) => m !== 0).length;

  const tabValid =
    tab === "fill"
      ? fillA.trim() !== "" && fillB.trim() !== "" && fillC.trim() !== ""
      : tab === "draw"
        ? markCount > 0
        : choices.size > 0 || customText.trim() !== "";

  const buildExpression = (): string => {
    if (tab === "fill")
      return `一年有 ${fillA} 天，31 天的月份叫${fillB}，闰年 2 月有 ${fillC} 天`;
    if (tab === "draw") {
      const big = marks.filter((m) => m === 1).length;
      const small = marks.filter((m) => m === 2).length;
      return `我标了 ${big} 个大月、${small} 个小月`;
    }
    const parts: string[] = [];
    choices.forEach((k) => {
      const opt = CHOICE_OPTIONS.find((o) => o.key === k);
      if (opt) parts.push(opt.text);
    });
    if (customText.trim()) parts.push(`我的发现：${customText.trim()}`);
    return parts.length ? parts.join("；") : "";
  };

  // ===== 第三层：验证 =====
  const [expression, setExpression] = useState("");
  const [revealCount, setRevealCount] = useState(0);

  useEffect(() => {
    if (layer !== "verify") return;
    if (revealCount >= REVEAL_STEPS.length) return;
    const id = setTimeout(() => setRevealCount((p) => p + 1), 750);
    return () => clearTimeout(id);
  }, [layer, revealCount]);

  // 根据已揭示步数计算各月份状态
  const litBig = new Set<number>();
  const litSmall = new Set<number>();
  let showSaying = false;
  let sayingText = "";
  let showFeb = false;
  let febText = "";
  for (let i = 0; i < revealCount && i < REVEAL_STEPS.length; i++) {
    const s = REVEAL_STEPS[i];
    if (s.type === "big") {
      litBig.add(s.monthIdx);
    } else if (s.type === "small") {
      litSmall.add(s.monthIdx);
    } else if (s.type === "saying") {
      showSaying = true;
      sayingText = s.text;
    } else if (s.type === "feb") {
      showFeb = true;
      febText = s.text;
    }
  }
  const revealDone = revealCount >= REVEAL_STEPS.length;

  const goVerify = () => {
    setExpression(buildExpression());
    setRevealCount(0);
    setLayer("verify");
  };

  const replay = () => {
    setLayer("review");
    setReviewIdx(0);
    setTab("fill");
    setFillA("");
    setFillB("");
    setFillC("");
    setMarks(Array.from({ length: 12 }, () => 0));
    setChoices(new Set());
    setCustomText("");
    setExpression("");
    setRevealCount(0);
  };

  const toggleChoice = (key: string) => {
    setChoices((prev) => {
      const next = new Set(prev);
      if (next.has(key)) next.delete(key);
      else next.add(key);
      return next;
    });
  };

  const cycleMark = (i: number) => {
    setMarks((prev) => {
      const next = [...prev];
      next[i] = ((next[i] + 1) % 3) as MarkState;
      return next;
    });
  };

  return (
    <StepShell topicId="calendar" stepId="discover">
      <div className="space-y-6">
        {/* ===== 第一层：回顾 ===== */}
        {layer === "review" && (
          <div className="space-y-6">
            <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
              <h2 className="text-center text-lg font-semibold text-[var(--text)]">
                我们一起走过的路
              </h2>
              <p className="mt-1 text-center text-sm text-[var(--text-secondary)]">
                回顾这 6 步，你做了好多事！
              </p>

              <div className="mt-6 flex min-h-[150px] items-center justify-center">
                {reviewIdx < REVIEW_ITEMS.length ? (
                  <div
                    key={reviewIdx}
                    className="animate-float-in flex flex-col items-center text-center"
                  >
                    <div className="text-5xl animate-bounce-soft">
                      {REVIEW_ITEMS[reviewIdx].icon}
                    </div>
                    <p className="mt-3 text-lg font-medium text-[var(--text)]">
                      {REVIEW_ITEMS[reviewIdx].step}. {REVIEW_ITEMS[reviewIdx].label}
                    </p>
                    <p className="mt-1 text-[var(--text-secondary)]">
                      {REVIEW_ITEMS[reviewIdx].text}
                    </p>
                  </div>
                ) : (
                  <div className="animate-float-in flex flex-col items-center text-center">
                    <div className="text-4xl">🌟</div>
                    <p className="mt-2 text-lg font-semibold text-[var(--text)]">
                      6 步走完啦！
                    </p>
                  </div>
                )}
              </div>

              {/* 进度点 */}
              <div className="mt-4 flex justify-center gap-2">
                {REVIEW_ITEMS.map((it, i) => (
                  <div
                    key={it.step}
                    className={`h-2 w-2 rounded-full transition-colors ${
                      i < reviewIdx
                        ? "bg-[var(--signal-confirmed)]"
                        : i === reviewIdx
                          ? "bg-[var(--signal-focus)]"
                          : "bg-[var(--signal-pending)]"
                    }`}
                  />
                ))}
              </div>
            </section>

            {reviewDone && (
              <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-focus)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
                <p className="text-center text-sm font-medium text-[var(--text)]">
                  你发现了什么规律？说出来吧！
                </p>
                <div className="mt-6 text-center">
                  <button
                    onClick={() => setLayer("express")}
                    className="rounded-full bg-[var(--signal-confirmed)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
                  >
                    说说我的发现 →
                  </button>
                </div>
              </section>
            )}
          </div>
        )}

        {/* ===== 第二层：表达发现 ===== */}
        {layer === "express" && (
          <div className="space-y-6">
            <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
              <h2 className="text-center text-lg font-semibold text-[var(--text)]">
                你发现了什么？
              </h2>
              <p className="mt-1 text-center text-sm text-[var(--text-secondary)]">
                选一种你喜欢的方式表达出来（三选一）
              </p>
            </section>

            {/* 选项卡 */}
            <div className="flex justify-center gap-2">
              {(
                [
                  { key: "fill", icon: "🖊️", label: "填写" },
                  { key: "draw", icon: "🎨", label: "画图" },
                  { key: "choose", icon: "💬", label: "选择" },
                ] as { key: ExpressTab; icon: string; label: string }[]
              ).map((t) => (
                <button
                  key={t.key}
                  onClick={() => setTab(t.key)}
                  className={`rounded-full px-5 py-2 text-sm font-medium transition-all ${
                    tab === t.key
                      ? "bg-[var(--signal-focus)] text-[var(--text)] shadow-[var(--shadow-sm)]"
                      : "bg-[var(--bg-soft)] text-[var(--text-secondary)] hover:bg-[var(--signal-focus)]/30"
                  }`}
                >
                  {t.icon} {t.label}
                </button>
              ))}
            </div>

            {/* 填写 */}
            {tab === "fill" && (
              <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
                <p className="text-center text-sm text-[var(--text-secondary)]">
                  我发现：
                </p>
                <div className="mt-4 space-y-4 text-lg font-bold text-[var(--text)]">
                  <div className="flex flex-wrap items-center justify-center gap-2">
                    <span>一年有</span>
                    <input
                      type="text"
                      inputMode="numeric"
                      value={fillA}
                      onChange={(e) => setFillA(e.target.value.replace(/[^0-9]/g, ""))}
                      className="w-20 rounded-lg border-2 border-[var(--border)] px-2 py-2 text-center text-lg font-bold text-[var(--text)] focus:border-[var(--primary)] focus:outline-none"
                      placeholder="365 / 366"
                      autoFocus
                    />
                    <span>天</span>
                  </div>
                  <div className="flex flex-wrap items-center justify-center gap-2">
                    <span>有 31 天的月份叫</span>
                    <input
                      type="text"
                      value={fillB}
                      onChange={(e) => setFillB(e.target.value)}
                      className="w-24 rounded-lg border-2 border-[var(--border)] px-2 py-2 text-center text-lg font-bold text-[var(--text)] focus:border-[var(--primary)] focus:outline-none"
                      placeholder="？"
                    />
                  </div>
                  <div className="flex flex-wrap items-center justify-center gap-2">
                    <span>闰年 2 月有</span>
                    <input
                      type="text"
                      inputMode="numeric"
                      value={fillC}
                      onChange={(e) => setFillC(e.target.value.replace(/[^0-9]/g, ""))}
                      className="w-20 rounded-lg border-2 border-[var(--border)] px-2 py-2 text-center text-lg font-bold text-[var(--text)] focus:border-[var(--primary)] focus:outline-none"
                      placeholder="？"
                    />
                    <span>天</span>
                  </div>
                </div>
                <p className="mt-4 text-center text-xs text-[var(--text-muted)]">
                  试着把年月日的秘密填完整
                </p>
              </section>
            )}

            {/* 画图：12 个月标注 */}
            {tab === "draw" && (
              <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
                <p className="text-center text-sm text-[var(--text-secondary)]">
                  点击每个月份，标注它是大月（31 天）还是小月（30 天）
                </p>
                <div
                  className="mx-auto mt-4 grid w-full max-w-[420px] gap-2"
                  style={{ gridTemplateColumns: "repeat(4, 1fr)" }}
                >
                  {MONTHS.map((m, i) => {
                    const state = marks[i];
                    const isFeb = i === 1;
                    return (
                      <button
                        key={i}
                        type="button"
                        onClick={() => cycleMark(i)}
                        className={`flex aspect-square flex-col items-center justify-center gap-1 rounded-xl border-2 text-sm font-bold transition-all duration-150 ${
                          state === 1
                            ? "border-[var(--signal-confirmed)] bg-[var(--signal-confirmed)]/20 text-[var(--primary)]"
                            : state === 2
                              ? "border-[var(--signal-success)] bg-[var(--signal-success)]/20 text-[var(--signal-success)]"
                              : "border-dashed border-[var(--signal-pending)] text-[var(--text-secondary)] hover:border-[var(--signal-focus)] hover:bg-[var(--signal-focus)]/20"
                        }`}
                      >
                        <span>{m}</span>
                        {isFeb && (
                          <span className="text-[10px] font-normal text-[var(--text-muted)]">
                            特殊
                          </span>
                        )}
                        {!isFeb && state === 1 && <span>31 天</span>}
                        {!isFeb && state === 2 && <span>30 天</span>}
                        {!isFeb && state === 0 && <span className="text-[var(--text-muted)]">？</span>}
                      </button>
                    );
                  })}
                </div>
                {/* 图例 */}
                <div className="mt-4 flex flex-wrap items-center justify-center gap-4 text-xs text-[var(--text-secondary)]">
                  <span className="inline-flex items-center gap-1.5">
                    <span className="h-2.5 w-2.5 rounded bg-[var(--signal-confirmed)]" />
                    大月 31 天
                  </span>
                  <span className="inline-flex items-center gap-1.5">
                    <span className="h-2.5 w-2.5 rounded bg-[var(--signal-success)]" />
                    小月 30 天
                  </span>
                  <span>已标 {markCount} 个</span>
                  {markCount > 0 && (
                    <button
                      onClick={() => setMarks(Array.from({ length: 12 }, () => 0))}
                      className="text-[var(--text-muted)] underline"
                    >
                      清空
                    </button>
                  )}
                </div>
              </section>
            )}

            {/* 选择 */}
            {tab === "choose" && (
              <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
                <p className="mb-3 text-center text-sm text-[var(--text-secondary)]">
                  以下哪些是你也认同的发现？（可多选）
                </p>
                <div className="space-y-3">
                  {CHOICE_OPTIONS.map((opt) => {
                    const selected = choices.has(opt.key);
                    return (
                      <button
                        key={opt.key}
                        onClick={() => toggleChoice(opt.key)}
                        className={`flex w-full items-center gap-3 rounded-lg border-2 px-4 py-3 text-left transition-all ${
                          selected
                            ? "border-[var(--signal-focus)] bg-[var(--signal-focus)]/20"
                            : "border-[var(--border)] bg-[var(--bg-soft)] hover:border-[var(--signal-focus)]/50"
                        }`}
                      >
                        <span
                          className={`flex h-7 w-7 shrink-0 items-center justify-center rounded-full text-sm font-bold transition-colors ${
                            selected
                              ? "bg-[var(--signal-focus)] text-[var(--text)]"
                              : "bg-[var(--bg-card)] text-[var(--text)]"
                          }`}
                        >
                          {selected ? "✓" : opt.key}
                        </span>
                        <span className="text-[var(--text)]">{opt.text}</span>
                      </button>
                    );
                  })}

                  {/* D 自定义 */}
                  <div
                    className={`flex items-center gap-3 rounded-lg border-2 px-4 py-3 transition-all ${
                      customText.trim()
                        ? "border-[var(--signal-focus)] bg-[var(--signal-focus)]/20"
                        : "border-[var(--border)] bg-[var(--bg-soft)]"
                    }`}
                  >
                    <span className="flex h-7 w-7 shrink-0 items-center justify-center rounded-full bg-[var(--bg-card)] text-sm font-bold text-[var(--text)]">
                      D
                    </span>
                    <input
                      type="text"
                      value={customText}
                      onChange={(e) => setCustomText(e.target.value)}
                      placeholder="我想说……"
                      className="flex-1 bg-transparent text-[var(--text)] placeholder:text-[var(--text-muted)] focus:outline-none"
                    />
                  </div>
                </div>
              </section>
            )}

            {/* 下一步 */}
            <div className="flex justify-center">
              <button
                onClick={goVerify}
                disabled={!tabValid}
                className="rounded-full bg-[var(--signal-confirmed)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)] disabled:cursor-not-allowed disabled:opacity-40 disabled:hover:translate-y-0"
              >
                看看口诀怎么说 →
              </button>
            </div>
          </div>
        )}

        {/* ===== 第三层：验证 ===== */}
        {layer === "verify" && (
          <div className="space-y-6">
            <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
              <h2 className="text-center text-lg font-semibold text-[var(--text)]">
                来验证一下你的发现
              </h2>
              <p className="mt-1 text-center text-sm text-[var(--text-secondary)]">
                一起念口诀，看看月份的天数规律
              </p>

              {/* 口诀文字 */}
              <div className="mt-6 text-center">
                <p className="text-2xl font-bold tracking-wider text-[var(--text)]">
                  {KOUJUE_CHARS.map((ch, i) => {
                    const revealed = i < litBig.size;
                    return (
                      <span
                        key={i}
                        className={`mx-0.5 inline-block transition-all duration-300 ${
                          revealed
                            ? "scale-110 text-[var(--primary)]"
                            : "text-[var(--text-muted)]"
                        }`}
                      >
                        {ch}
                      </span>
                    );
                  })}
                  <span className="mx-1">，</span>
                  <span
                    className={`inline-block transition-all duration-300 ${
                      showSaying ? "scale-110 text-[var(--accent)]" : "text-[var(--text-muted)]"
                    }`}
                  >
                    三十一年永不差
                  </span>
                </p>
                <p className="mt-1 text-xs text-[var(--text-muted)]">
                  腊 = 12 月
                </p>
              </div>

              {/* 12 个月格子 */}
              <div
                className="mx-auto mt-5 grid w-full max-w-[420px] gap-2"
                style={{ gridTemplateColumns: "repeat(4, 1fr)" }}
              >
                {MONTHS.map((m, i) => {
                  const isBig = litBig.has(i);
                  const isSmall = litSmall.has(i);
                  const isFeb = i === 1;
                  return (
                    <div
                      key={i}
                      className={`flex aspect-square flex-col items-center justify-center gap-0.5 rounded-xl border-2 text-sm font-bold transition-all duration-300 ${
                        isBig
                          ? "border-[var(--signal-confirmed)] bg-[var(--signal-confirmed)]/20 text-[var(--primary)]"
                          : isSmall
                            ? "border-[var(--signal-success)] bg-[var(--signal-success)]/20 text-[var(--signal-success)]"
                            : isFeb && showFeb
                              ? "border-[var(--accent3)] bg-[var(--accent3)]/20 text-[var(--accent3)]"
                              : "border-dashed border-[var(--signal-pending)] text-[var(--text-muted)]"
                      }`}
                    >
                      <span>{m}</span>
                      {isBig && <span className="text-xs">31 天</span>}
                      {isSmall && <span className="text-xs">30 天</span>}
                      {isFeb && showFeb && <span className="text-xs">28/29</span>}
                    </div>
                  );
                })}
              </div>

              {/* 小结提示 */}
              <div className="mt-4 space-y-2">
                {showSaying && (
                  <p className="animate-float-in rounded-lg bg-[var(--signal-focus)]/15 px-4 py-2 text-center text-sm font-medium text-[var(--text)]">
                    {sayingText}
                  </p>
                )}
                {showFeb && (
                  <p className="animate-float-in rounded-lg bg-[var(--accent3)]/15 px-4 py-2 text-center text-sm font-medium text-[var(--text)]">
                    {febText}
                  </p>
                )}
              </div>
            </section>

            {/* 完成提示 */}
            {revealDone && (
              <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
                <div className="text-4xl animate-bounce-soft">💡</div>
                <p className="mt-3 text-[var(--text)]">
                  口诀和你的发现一模一样！
                </p>
                <p className="mt-1 text-sm text-[var(--text-secondary)]">
                  大月 7 个、小月 4 个，2 月最特别
                </p>
                <div className="mt-6 flex justify-center">
                  <button
                    onClick={() => setLayer("card")}
                    className="animate-float-in rounded-full bg-[var(--accent)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5"
                  >
                    查看发现卡 →
                  </button>
                </div>
              </section>
            )}
          </div>
        )}

        {/* ===== 第四层：发现卡 ===== */}
        {layer === "card" && (
          <div className="space-y-6">
            {/* 渐变边框卡片 */}
            <div className="relative animate-float-in">
              {/* 渐变背景层 */}
              <div
                className="absolute -inset-[2px] rounded-[calc(var(--radius)+2px)]"
                style={{
                  background:
                    "linear-gradient(135deg, var(--signal-confirmed), var(--primary), var(--accent3), var(--accent))",
                  opacity: 0.9,
                }}
              />
              {/* 内层卡片 */}
              <div className="relative rounded-[var(--radius)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-lg)]">
                {/* 卡头 */}
                <div className="flex items-center justify-between border-b border-dashed border-[var(--border)] pb-4">
                  <div className="flex items-center gap-2">
                    <span className="text-2xl">🌟</span>
                    <div>
                      <h3 className="text-lg font-bold text-[var(--text)]">
                        我的年月日发现卡
                      </h3>
                      <p className="text-xs text-[var(--text-muted)]">
                        年、月、日的秘密 · 七步探索
                      </p>
                    </div>
                  </div>
                  <span className="rounded-full bg-[var(--signal-focus)] px-3 py-1 text-xs font-bold text-[var(--text)]">
                    完成
                  </span>
                </div>

                {/* 我的表达 */}
                <div className="mt-4">
                  <p className="text-xs font-medium text-[var(--text-muted)]">
                    我的发现
                  </p>
                  <p className="mt-1 rounded-lg bg-[var(--bg-soft)] px-4 py-3 text-[var(--text)]">
                    {expression || "我发现了年月日的秘密！"}
                  </p>
                </div>

                {/* 三个要点 */}
                <div className="mt-4 space-y-2">
                  <div className="flex items-start gap-2 rounded-lg border border-[var(--border)] bg-[var(--bg-soft)] px-4 py-3">
                    <span className="mt-0.5 text-[var(--signal-confirmed)]">✓</span>
                    <span className="text-[var(--text)]">
                      一年有 12 个月，平年 365 天，闰年 366 天
                    </span>
                  </div>
                  <div className="flex items-start gap-2 rounded-lg border border-[var(--border)] bg-[var(--bg-soft)] px-4 py-3">
                    <span className="mt-0.5 text-[var(--signal-confirmed)]">✓</span>
                    <span className="text-[var(--text)]">
                      “一三五七八十腊，三十一天永不差”
                    </span>
                  </div>
                  <div className="flex items-start gap-2 rounded-lg border border-[var(--border)] bg-[var(--bg-soft)] px-4 py-3">
                    <span className="mt-0.5 text-[var(--signal-confirmed)]">✓</span>
                    <span className="text-[var(--text)]">
                      闰年 2 月 29 天，每 4 年一个闰年
                    </span>
                  </div>
                </div>

                {/* 口诀高亮 */}
                <div className="mt-4 rounded-lg border-2 border-[var(--signal-focus)] bg-[var(--signal-focus)]/10 px-4 py-4 text-center">
                  <p className="text-xs text-[var(--text-secondary)]">
                    记忆口诀
                  </p>
                  <p className="mt-1 text-xl font-bold tracking-wider text-[var(--primary)]">
                    一三五七八十腊
                  </p>
                  <p className="text-xl font-bold tracking-wider text-[var(--primary)]">
                    三十一天永不差
                  </p>
                </div>

                {/* 回顾六步 */}
                <div className="mt-4">
                  <p className="text-xs font-medium text-[var(--text-muted)]">
                    我走过的 6 步
                  </p>
                  <div className="mt-2 flex flex-wrap gap-2">
                    {REVIEW_ITEMS.map((it) => (
                      <span
                        key={it.step}
                        className="inline-flex items-center gap-1 rounded-full bg-[var(--bg-soft)] px-2.5 py-1 text-xs text-[var(--text-secondary)]"
                      >
                        <span>{it.icon}</span>
                        {it.label}
                      </span>
                    ))}
                  </div>
                </div>

                {/* 卡尾 */}
                <div className="mt-5 flex items-center justify-between border-t border-dashed border-[var(--border)] pt-4">
                  <span className="text-xs text-[var(--text-muted)]">
                    {completeMsg}
                  </span>
                  <span className="text-xs text-[var(--text-muted)]">
                    🎉 数学好好玩
                  </span>
                </div>
              </div>
            </div>

            <p className="text-center text-xs text-[var(--text-muted)]">
              💡 提示：可以截图保存这张卡片哦
            </p>

            <div className="space-y-3 text-center">
              <p className="text-sm text-[var(--text-secondary)]">
                🎉 你已经完成了年、月、日的秘密的全部学习！
              </p>
              <div className="flex flex-wrap items-center justify-center gap-3">
                <button
                  onClick={replay}
                  className="rounded-full border border-[var(--border)] bg-[var(--bg-soft)] px-5 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-card)]"
                >
                  再玩一次
                </button>
                <Link
                  href="/learn/calendar"
                  className="rounded-full bg-[var(--signal-confirmed)] px-5 py-2 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5"
                >
                  回到年月日主页
                </Link>
              </div>
            </div>
          </div>
        )}
      </div>
    </StepShell>
  );
}
